/// Fold (icmp ne X, C) & (icmp ule (X - C), Y) --> icmp ult (X - (C+1)), Y
/// Fold (icmp eq X, C) | (icmp ugt (X - C), Y) --> icmp uge (X - (C+1)), Y
/// This handles the pattern where we check that X-C doesn't underflow (X != C)
/// and X-C <= Y, which is equivalent to X-(C+1) < Y.
/// Also handles the special case where C = -1 (all ones):
/// Fold (icmp ne X, -1) & (icmp ule (X + 1), Y) --> icmp ult X, Y
/// Fold (icmp eq X, -1) | (icmp ugt (X + 1), Y) --> icmp uge X, Y
static Value *foldUnsignedOverflowCheck(ICmpInst *EqICmp,
                                        ICmpInst *UnsignedICmp, bool IsAnd,
                                        InstCombiner::BuilderTy &Builder) {
  // Match (icmp ne X, C) or (icmp eq X, C)
  Value *X;
  ConstantInt *C;
  ICmpInst::Predicate EqPred;
  if (!match(EqICmp, m_ICmp(EqPred, m_Value(X), m_ConstantInt(C))) ||
      !ICmpInst::isEquality(EqPred))
    return nullptr;

  // Match (icmp ule AddOp, Y) or (icmp ugt AddOp, Y) or commuted versions
  Value *AddOp;
  ICmpInst::Predicate UnsignedPred;
  if (!match(UnsignedICmp,
             m_c_ICmp(UnsignedPred, m_Value(AddOp), m_Value())) ||
      !ICmpInst::isUnsigned(UnsignedPred))
    return nullptr;

  // Get Y from the icmp (the operand that is not AddOp)
  Value *Y = UnsignedICmp->getOperand(0) == AddOp ? UnsignedICmp->getOperand(1)
                                                   : UnsignedICmp->getOperand(0);

  // Check that AddOp is (X + Offset) where Offset = -C
  const APInt *Offset;
  if (!match(AddOp, m_Add(m_Specific(X), m_APInt(Offset))))
    return nullptr;

  // The offset should be -C for the pattern to match
  // i.e., AddOp = X - C = X + (-C)
  if (*Offset != -C->getValue())
    return nullptr;

  // (icmp ne X, C) & (icmp ule (X - C), Y) --> icmp ult (X - (C+1)), Y
  // If X != C (no underflow) and X-C <= Y, then X-(C+1) < Y
  if (UnsignedPred == ICmpInst::ICMP_ULE && EqPred == ICmpInst::ICMP_NE &&
      IsAnd) {
    // Compute C+1
    bool Overflow;
    APInt CPlusOne = C->getValue().uadd_ov(1, Overflow);
    if (Overflow)
      return nullptr;
    // If C+1 overflows, then X-(C+1) is always X, so we get icmp ult X, Y
    // But this only happens when C is -1 (all ones)
    if (CPlusOne.isZero())
      return Builder.CreateICmpULT(X, Y);
    // Otherwise: icmp ult (X - (C+1)), Y
    Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(X->getType(), -CPlusOne));
    return Builder.CreateICmpULT(NewAdd, Y);
  }

  // (icmp eq X, C) | (icmp ugt (X - C), Y) --> icmp uge (X - (C+1)), Y
  // If X == C (underflow) or X-C > Y, then X-(C+1) >= Y
  if (UnsignedPred == ICmpInst::ICMP_UGT && EqPred == ICmpInst::ICMP_EQ &&
      !IsAnd) {
    // Compute C+1
    bool Overflow;
    APInt CPlusOne = C->getValue().uadd_ov(1, Overflow);
    if (Overflow)
      return nullptr;
    // If C+1 overflows, then X-(C+1) is always X, so we get icmp uge X, Y
    // But this only happens when C is -1 (all ones)
    if (CPlusOne.isZero())
      return Builder.CreateICmpUGE(X, Y);
    // Otherwise: icmp uge (X - (C+1)), Y
    Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(X->getType(), -CPlusOne));
    return Builder.CreateICmpUGE(NewAdd, Y);
  }

  return nullptr;
}
CODEEOF"}

